     1→/**
     2→ * Natural Language Recurrence Parser
     3→ * Converts human-readable phrases into RecurrenceRule objects
     4→ *
     5→ * Supported phrases:
     6→ * - Daily: "every day", "every 3 days", "daily", "every weekday"
     7→ * - Weekly: "every week", "every Monday", "every 2 weeks on Friday", "weekly"
     8→ * - Monthly: "every month", "every 15th", "monthly on the 10th"
     9→ * - Yearly: "every year", "annually", "every January 15th"
    10→ */
    11→
    12→import type { Task } from '../types';
    13→
    14→type RecurrenceRule = NonNullable<Task['recurrence']>;
    15→
    16→const DAY_NAMES: Record<string, number> = {
    17→  sunday: 0,
    18→  monday: 1,
    19→  tuesday: 2,
    20→  wednesday: 3,
    21→  thursday: 4,
    22→  friday: 5,
    23→  saturday: 6,
    24→  sun: 0,
    25→  mon: 1,
    26→  tue: 2,
    27→  wed: 3,
    28→  thu: 4,
    29→  fri: 5,
    30→  sat: 6,
    31→};
    32→
    33→const MONTH_NAMES: Record<string, number> = {
    34→  january: 1,
    35→  february: 2,
    36→  march: 3,
    37→  april: 4,
    38→  may: 5,
    39→  june: 6,
    40→  july: 7,
    41→  august: 8,
    42→  september: 9,
    43→  october: 10,
    44→  november: 11,
    45→  december: 12,
    46→  jan: 1,
    47→  feb: 2,
    48→  mar: 3,
    49→  apr: 4,
    50→  jun: 6,
    51→  jul: 7,
    52→  aug: 8,
    53→  sep: 9,
    54→  oct: 10,
    55→  nov: 11,
    56→  dec: 12,
    57→};
    58→
    59→/**
    60→ * Parse a natural language string into a RecurrenceRule
    61→ * @param input Human-readable recurrence description
    62→ * @returns RecurrenceRule object or null if unparseable
    63→ */
    64→export function parseRecurrenceNaturalLanguage(input: string): RecurrenceRule | null {
    65→  if (!input || typeof input !== 'string') {
    66→    return null;
    67→  }
    68→
    69→  const normalized = input.toLowerCase().trim().replace(/\s+/g, ' ');
    70→
    71→  return (
    72→    parseDailyPattern(normalized) ||
    73→    parseWeeklyPattern(normalized) ||
    74→    parseMonthlyPattern(normalized) ||
    75→    parseYearlyPattern(normalized)
    76→  );
    77→}
    78→
    79→function parseDailyPattern(input: string): RecurrenceRule | null {
    80→  // "every weekday" or "weekdays"
    81→  if (input.includes('weekday')) {
    82→    return {
    83→      frequency: 'weekly',
    84→      interval: 1,
    85→      daysOfWeek: [1, 2, 3, 4, 5], // Mon-Fri
    86→      endType: 'never',
    87→    };
    88→  }
    89→
    90→  // "every day" or "daily"
    91→  if (input === 'every day' || input === 'daily') {
    92→    return {
    93→      frequency: 'daily',
    94→      interval: 1,
    95→      endType: 'never',
    96→    };
    97→  }
    98→
    99→  // "every N days" or "every N day"
   100→  const everyNDays = input.match(/every (\d+) days?/);
   101→  if (everyNDays) {
   102→    const interval = parseInt(everyNDays[1], 10);
   103→    if (interval < 1 || interval > 100) return null; // Validate interval
   104→    return {
   105→      frequency: 'daily',
   106→      interval,
   107→      endType: 'never',
   108→    };
   109→  }
   110→
   111→  return null;
   112→}
   113→
   114→function parseWeeklyPattern(input: string): RecurrenceRule | null {
   115→  // "every week" or "weekly"
   116→  if (input === 'every week' || input === 'weekly') {
   117→    return {
   118→      frequency: 'weekly',
   119→      interval: 1,
   120→      endType: 'never',
   121→    };
   122→  }
   123→
   124→  // "every N weeks" (without specific day)
   125→  const everyNWeeks = input.match(/every (\d+) weeks?$/);
   126→  if (everyNWeeks) {
   127→    const interval = parseInt(everyNWeeks[1], 10);
   128→    if (interval < 1 || interval > 100) return null; // Validate interval
   129→    return {
   130→      frequency: 'weekly',
   131→      interval,
   132→      endType: 'never',
   133→    };
   134→  }
   135→
   136→  // "every <day>" (e.g., "every monday")
   137→  for (const [dayName, dayNum] of Object.entries(DAY_NAMES)) {
   138→    if (input === `every ${dayName}`) {
   139→      return {
   140→        frequency: 'weekly',
   141→        interval: 1,
   142→        daysOfWeek: [dayNum],
   143→        endType: 'never',
   144→      };
   145→    }
   146→  }
   147→
   148→  // "every N weeks on <day>" (e.g., "every 2 weeks on friday")
   149→  for (const [dayName, dayNum] of Object.entries(DAY_NAMES)) {
   150→    const pattern = `every (\\d+) weeks? on ${dayName}`;
   151→    const match = input.match(new RegExp(pattern));
   152→    if (match) {
   153→      const interval = parseInt(match[1], 10);
   154→      if (interval < 1 || interval > 100) return null; // Validate interval
   155→      return {
   156→        frequency: 'weekly',
   157→        interval,
   158→        daysOfWeek: [dayNum],
   159→        endType: 'never',
   160→      };
   161→    }
   162→  }
   163→
   164→  return null;
   165→}
   166→
   167→function parseMonthlyPattern(input: string): RecurrenceRule | null {
   168→  // "every month" or "monthly"
   169→  if (input === 'every month' || input === 'monthly') {
   170→    return {
   171→      frequency: 'monthly',
   172→      interval: 1,
   173→      endType: 'never',
   174→    };
   175→  }
   176→
   177→  // "every N months on the Nth" (e.g., "every 3 months on the 15th")
   178→  const everyNMonthsOnThe = input.match(/every (\d+) months? on the (\d+)(?:st|nd|rd|th)?/);
   179→  if (everyNMonthsOnThe) {
   180→    const interval = parseInt(everyNMonthsOnThe[1], 10);
   181→    const day = parseInt(everyNMonthsOnThe[2], 10);
   182→    if (interval < 1 || interval > 100) return null; // Validate interval
   183→    if (day >= 1 && day <= 31) {
   184→      return {
   185→        frequency: 'monthly',
   186→        interval,
   187→        dayOfMonth: day,
   188→        endType: 'never',
   189→      };
   190→    }
   191→  }
   192→
   193→  // "every Nth" or "every Nst" or "every Nnd" or "every Nrd" (e.g., "every 15th")
   194→  const everyNth = input.match(/every (\d+)(?:st|nd|rd|th)?$/);
   195→  if (everyNth) {
   196→    const day = parseInt(everyNth[1], 10);
   197→    if (day >= 1 && day <= 31) {
   198→      return {
   199→        frequency: 'monthly',
   200→        interval: 1,
   201→        dayOfMonth: day,
   202→        endType: 'never',
   203→      };
   204→    }
   205→  }
   206→
   207→  // "monthly on the Nth" (e.g., "monthly on the 10th")
   208→  const monthlyOnThe = input.match(/monthly on the (\d+)(?:st|nd|rd|th)?/);
   209→  if (monthlyOnThe) {
   210→    const day = parseInt(monthlyOnThe[1], 10);
   211→    if (day >= 1 && day <= 31) {
   212→      return {
   213→        frequency: 'monthly',
   214→        interval: 1,
   215→        dayOfMonth: day,
   216→        endType: 'never',
   217→      };
   218→    }
   219→  }
   220→
   221→  // "every N months"
   222→  const everyNMonths = input.match(/every (\d+) months?$/);
   223→  if (everyNMonths) {
   224→    const interval = parseInt(everyNMonths[1], 10);
   225→    if (interval < 1 || interval > 100) return null; // Validate interval
   226→    return {
   227→      frequency: 'monthly',
   228→      interval,
   229→      endType: 'never',
   230→    };
   231→  }
   232→
   233→  return null;
   234→}
   235→
   236→function parseYearlyPattern(input: string): RecurrenceRule | null {
   237→  // "every year" or "annually" or "yearly"
   238→  if (input === 'every year' || input === 'annually' || input === 'yearly') {
   239→    return {
   240→      frequency: 'yearly',
   241→      interval: 1,
   242→      endType: 'never',
   243→    };
   244→  }
   245→
   246→  // "every N years"
   247→  const everyNYears = input.match(/every (\d+) years?$/);
   248→  if (everyNYears) {
   249→    const interval = parseInt(everyNYears[1], 10);
   250→    if (interval < 1 || interval > 100) return null; // Validate interval
   251→    return {
   252→      frequency: 'yearly',
   253→      interval,
   254→      endType: 'never',
   255→    };
   256→  }
   257→
   258→  // "every <month> <day>" (e.g., "every january 15th")
   259→  // Note: RecurrenceRule type doesn't currently support monthOfYear field,
   260→  // so we can only return basic yearly recurrence without the specific month/day
   261→  for (const [monthName] of Object.entries(MONTH_NAMES)) {
   262→    const pattern = `every ${monthName} (\\d+)(?:st|nd|rd|th)?`;
   263→    const match = input.match(new RegExp(pattern));
   264→    if (match) {
   265→      const day = parseInt(match[1], 10);
   266→      if (day >= 1 && day <= 31) {
   267→        // TODO: Add monthOfYear field to RecurrenceRule type to fully support this
   268→        return {
   269→          frequency: 'yearly',
   270→          interval: 1,
   271→          endType: 'never',
   272→        };
   273→      }
   274→    }
   275→  }
   276→
   277→  return null;
   278→}
   279→
   280→/**
   281→ * Format a RecurrenceRule into human-readable text
   282→ * @param rule RecurrenceRule object
   283→ * @returns Human-readable string
   284→ */
   285→export function formatRecurrenceRule(rule: RecurrenceRule): string {
   286→  const { frequency, interval = 1, daysOfWeek, dayOfMonth } = rule;
   287→
   288→  // Daily patterns
   289→  if (frequency === 'daily') {
   290→    if (interval === 1) {
   291→      return 'Every day';
   292→    }
   293→    return `Every ${interval} days`;
   294→  }
   295→
   296→  // Weekly patterns
   297→  if (frequency === 'weekly') {
   298→    // Weekdays
   299→    if (daysOfWeek && daysOfWeek.length === 5 && daysOfWeek.includes(1) && daysOfWeek.includes(5)) {
   300→      return 'Every weekday';
   301→    }
   302→
   303→    // Specific day(s)
   304→    if (daysOfWeek && daysOfWeek.length > 0) {
   305→      const dayNames = daysOfWeek.map(d => getDayName(d));
   306→      const dayStr = dayNames.join(', ');
   307→      if (interval === 1) {
   308→        return `Every ${dayStr}`;
   309→      }
   310→      return `Every ${interval} weeks on ${dayStr}`;
   311→    }
   312→
   313→    // No specific days
   314→    if (interval === 1) {
   315→      return 'Every week';
   316→    }
   317→    return `Every ${interval} weeks`;
   318→  }
   319→
   320→  // Monthly patterns
   321→  if (frequency === 'monthly') {
   322→    if (dayOfMonth) {
   323→      if (interval === 1) {
   324→        return `Every ${dayOfMonth}${getOrdinalSuffix(dayOfMonth)}`;
   325→      }
   326→      return `Every ${interval} months on the ${dayOfMonth}${getOrdinalSuffix(dayOfMonth)}`;
   327→    }
   328→
   329→    if (interval === 1) {
   330→      return 'Every month';
   331→    }
   332→    return `Every ${interval} months`;
   333→  }
   334→
   335→  // Yearly patterns
   336→  if (frequency === 'yearly') {
   337→    if (interval === 1) {
   338→      return 'Every year';
   339→    }
   340→    return `Every ${interval} years`;
   341→  }
   342→
   343→  return 'Custom recurrence';
   344→}
   345→
   346→function getDayName(dayNum: number): string {
   347→  const names = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
   348→  return names[dayNum] || '';
   349→}
   350→
   351→function getOrdinalSuffix(n: number): string {
   352→  if (n >= 11 && n <= 13) return 'th';
   353→  const lastDigit = n % 10;
   354→  if (lastDigit === 1) return 'st';
   355→  if (lastDigit === 2) return 'nd';
   356→  if (lastDigit === 3) return 'rd';
   357→  return 'th';
   358→}
   359→

