     1→/**
     2→ * Task Recurrence Service
     3→ * Handles generation and calculation of recurring task instances
     4→ */
     5→
     6→import { format, addDays, addWeeks, addMonths, addYears, isBefore, isAfter, parseISO, startOfDay } from 'date-fns';
     7→import type { Task } from '../types';
     8→import { logger } from './logger';
     9→import { useTemplateStore } from '../stores/useTemplateStore';
    10→
    11→const log = logger.module('TaskRecurrence');
    12→
    13→/**
    14→ * Calculate the next occurrence date based on recurrence rules
    15→ * @param task Task with recurrence rules
    16→ * @param fromDate Starting date (YYYY-MM-DD)
    17→ * @returns Next occurrence date (YYYY-MM-DD) or null if series has ended
    18→ */
    19→export function calculateNextOccurrence(task: Task, fromDate: string): string | null {
    20→  if (!task.recurrence) return null;
    21→
    22→  const { frequency, interval, daysOfWeek, dayOfMonth, endType, endDate } = task.recurrence;
    23→  let nextDate = parseISO(fromDate);
    24→
    25→  // Add interval based on frequency
    26→  switch (frequency) {
    27→    case 'daily':
    28→      nextDate = addDays(nextDate, interval);
    29→      break;
    30→
    31→    case 'weekly':
    32→      // For weekly, find next matching day of week
    33→      if (daysOfWeek && daysOfWeek.length > 0) {
    34→        const currentDay = nextDate.getDay();
    35→        let daysToAdd = interval * 7;
    36→
    37→        // Find next matching day in the cycle
    38→        const sortedDays = [...daysOfWeek].sort((a, b) => a - b);
    39→        const nextMatchingDay = sortedDays.find(day => day > currentDay);
    40→
    41→        if (nextMatchingDay !== undefined) {
    42→          // Next occurrence is this week
    43→          daysToAdd = nextMatchingDay - currentDay;
    44→        } else {
    45→          // Next occurrence is next week (first day in cycle)
    46→          daysToAdd = (interval - 1) * 7 + (7 - currentDay + sortedDays[0]);
    47→        }
    48→
    49→        nextDate = addDays(nextDate, daysToAdd);
    50→      } else {
    51→        nextDate = addWeeks(nextDate, interval);
    52→      }
    53→      break;
    54→
    55→    case 'monthly':
    56→      nextDate = addMonths(nextDate, interval);
    57→
    58→      // If specific day of month is set, adjust
    59→      if (dayOfMonth) {
    60→        const targetDay = Math.min(dayOfMonth, new Date(nextDate.getFullYear(), nextDate.getMonth() + 1, 0).getDate());
    61→        nextDate.setDate(targetDay);
    62→      }
    63→      break;
    64→
    65→    case 'yearly':
    66→      nextDate = addYears(nextDate, interval);
    67→      break;
    68→  }
    69→
    70→  const nextDateStr = format(nextDate, 'yyyy-MM-dd');
    71→
    72→  // Check if series has ended
    73→  if (endType === 'until' && endDate) {
    74→    if (isAfter(nextDate, parseISO(endDate))) {
    75→      log.debug('Series ended by date', { endDate, nextDate: nextDateStr });
    76→      return null;
    77→    }
    78→  }
    79→
    80→  // Note: endCount is tracked per task completion, not calculated here
    81→
    82→  return nextDateStr;
    83→}
    84→
    85→/**
    86→ * Generate the next instance of a recurring task
    87→ * @param parentTask The parent/template task with recurrence rules
    88→ * @param lastCompletedInstance Optional: the last completed instance (for recurFromCompletion)
    89→ * @returns New task instance or null if series has ended
    90→ */
    91→export function generateNextInstance(parentTask: Task, lastCompletedInstance?: Task): Task | null {
    92→  if (!parentTask.recurrence || !parentTask.isRecurringParent) {
    93→    log.warn('Attempted to generate instance from non-recurring task', { taskId: parentTask.id });
    94→    return null;
    95→  }
    96→
    97→  // Calculate next occurrence from completion date (if recurFromCompletion) or due date
    98→  let fromDate: string;
    99→  if (parentTask.recurrence.recurFromCompletion && lastCompletedInstance?.lastCompletedAt) {
   100→    // Use completion date when recurFromCompletion is enabled
   101→    fromDate = format(new Date(lastCompletedInstance.lastCompletedAt), 'yyyy-MM-dd');
   102→    log.debug('Using completion date for next occurrence', { completionDate: fromDate });
   103→  } else {
   104→    // Default: use parent's nextOccurrence, due date, or today
   105→    fromDate = parentTask.nextOccurrence || parentTask.dueDate || format(new Date(), 'yyyy-MM-dd');
   106→  }
   107→
   108→  const nextOccurrenceDate = calculateNextOccurrence(parentTask, fromDate);
   109→
   110→  if (!nextOccurrenceDate) {
   111→    log.debug('No next occurrence (series ended)', { taskId: parentTask.id });
   112→    return null;
   113→  }
   114→
   115→  // Create new task instance
   116→  const instance: Task = {
   117→    ...parentTask,
   118→    id: `${parentTask.id}-${nextOccurrenceDate}`, // Unique ID per instance
   119→    recurrenceId: parentTask.id, // Link back to parent
   120→    isRecurringParent: false, // This is an instance, not parent
   121→    nextOccurrence: undefined, // Instances don't calculate next
   122→    dueDate: nextOccurrenceDate,
   123→    startDate: nextOccurrenceDate, // Could offset this by X days if needed
   124→    created: new Date().toISOString(),
   125→    status: 'todo', // Reset to todo
   126→    progress: 0, // Reset progress
   127→    lastCompletedAt: undefined,
   128→    archivedAt: undefined,
   129→  };
   130→
   131→  // P2: Apply template if templateId is set
   132→  if (parentTask.recurrence.templateId) {
   133→    const { getTemplate } = useTemplateStore.getState();
   134→    const template = getTemplate(parentTask.recurrence.templateId);
   135→
   136→    if (template) {
   137→      // Apply template fields
   138→      instance.description = template.description;
   139→      instance.tags = [...template.tags];
   140→
   141→      // Apply checklist with new IDs and reset completion status
   142→      if (template.checklist) {
   143→        instance.checklist = template.checklist.map(item => ({
   144→          ...item,
   145→          id: `${instance.id}-checklist-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
   146→          completed: false,
   147→        }));
   148→      }
   149→
   150→      // Apply custom fields
   151→      if (template.customFields) {
   152→        instance.customFields = { ...template.customFields };
   153→      }
   154→
   155→      log.info('Applied template to recurring instance', {
   156→        templateId: template.id,
   157→        templateName: template.name,
   158→        instanceId: instance.id,
   159→      });
   160→    } else {
   161→      log.warn('Template not found, continuing without template', {
   162→        templateId: parentTask.recurrence.templateId,
   163→        instanceId: instance.id,
   164→      });
   165→    }
   166→  }
   167→
   168→  log.info('Generated recurring task instance', {
   169→    parentId: parentTask.id,
   170→    instanceId: instance.id,
   171→    dueDate: nextOccurrenceDate
   172→  });
   173→
   174→  return instance;
   175→}
   176→
   177→/**
   178→ * Check if a new instance should be generated for a recurring task
   179→ * @param parentTask The parent recurring task
   180→ * @param allTasks All tasks in the system
   181→ * @returns True if new instance should be created
   182→ */
   183→export function shouldGenerateNextInstance(parentTask: Task, allTasks: Task[]): boolean {
   184→  if (!parentTask.recurrence || !parentTask.isRecurringParent) {
   185→    return false;
   186→  }
   187→
   188→  // Get all instances of this recurring task
   189→  const instances = getTaskInstances(parentTask, allTasks);
   190→
   191→  // Check if there's an incomplete instance with a future/today due date
   192→  const hasActiveInstance = instances.some(instance =>
   193→    instance.status !== 'done' &&
   194→    instance.dueDate &&
   195→    !isBefore(parseISO(instance.dueDate), startOfDay(new Date()))
   196→  );
   197→
   198→  if (hasActiveInstance) {
   199→    log.debug('Active instance exists, no new generation needed', { parentId: parentTask.id });
   200→    return false;
   201→  }
   202→
   203→  // Check endCount if applicable
   204→  if (parentTask.recurrence.endType === 'after' && parentTask.recurrence.endCount) {
   205→    const completedCount = instances.filter(i => i.status === 'done').length;
   206→    if (completedCount >= parentTask.recurrence.endCount) {
   207→      log.debug('Recurrence limit reached', {
   208→        parentId: parentTask.id,
   209→        completedCount,
   210→        endCount: parentTask.recurrence.endCount
   211→      });
   212→      return false;
   213→    }
   214→  }
   215→
   216→  log.debug('Should generate next instance', { parentId: parentTask.id });
   217→  return true;
   218→}
   219→
   220→/**
